.toolbar {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.3rem;
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 10px;
  background: rgba(0, 0, 0, 0.015);
}
.toolbar-group { display: inline-flex; gap: 0.15rem; }
.toolbar-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 2rem;
  height: 2rem;
  padding: 0 0.5rem;
  font: inherit;
  color: var(--color-text-main);
  background: none;
  border: 1px solid transparent;
  border-radius: 7px;
  cursor: pointer;
}
.toolbar-btn:hover { background: rgba(0, 0, 0, 0.05); }
.toolbar-btn:focus-visible {
  outline: 2px solid var(--color-primary, #2563eb);
  outline-offset: 1px;
}
.toolbar-btn[aria-pressed="true"] {
  background: var(--color-primary, #2563eb);
  color: #fff;
}
.toolbar-sep {
  width: 1px;
  align-self: stretch;
  margin: 0.2rem 0.15rem;
  background: var(--color-border, #e2e8f0);
}

/* toolbar.js (#859) — progressive enhancement for the W3C APG toolbar. Baseline
 * markup already keeps the toolbar to one Tab stop (first button tabindex=0, the
 * rest -1). This layers the roving-tabindex behaviour: Arrow keys move focus and
 * the tab stop between controls, Home/End jump to the ends, and toggle buttons
 * flip aria-pressed on activation.
 */
(function () {
  'use strict';
  Array.prototype.forEach.call(document.querySelectorAll('[data-toolbar]'), function (toolbar) {
    var vertical = toolbar.getAttribute('aria-orientation') === 'vertical';
    var items = function () {
      return Array.prototype.slice.call(toolbar.querySelectorAll('.toolbar-btn'));
    };
    var focusAt = function (list, i) {
      var n = (i + list.length) % list.length;
      list.forEach(function (b, j) { b.tabIndex = j === n ? 0 : -1; });
      list[n].focus();
    };

    toolbar.addEventListener('keydown', function (e) {
      var list = items();
      var i = list.indexOf(document.activeElement);
      if (i === -1) return;
      var next = vertical ? 'ArrowDown' : 'ArrowRight';
      var prev = vertical ? 'ArrowUp' : 'ArrowLeft';
      if (e.key === next) { e.preventDefault(); focusAt(list, i + 1); }
      else if (e.key === prev) { e.preventDefault(); focusAt(list, i - 1); }
      else if (e.key === 'Home') { e.preventDefault(); focusAt(list, 0); }
      else if (e.key === 'End') { e.preventDefault(); focusAt(list, list.length - 1); }
    });

    // Toggle buttons flip aria-pressed on click.
    toolbar.addEventListener('click', function (e) {
      var btn = e.target.closest('.toolbar-btn');
      if (btn && btn.hasAttribute('aria-pressed')) {
        btn.setAttribute('aria-pressed', btn.getAttribute('aria-pressed') === 'true' ? 'false' : 'true');
      }
    });
  });
})();
